sys_script.script:
(function executeRule(current, previous) {

    try {

        var history = new GlideRecord('x_2091449_manage_0_complaint_history');

        history.initialize();

        history.consumer_case = current.sys_id;

        history.action_type = 'updated';

        var changes = [];

        if (current.assignment_group.changes()) {
            changes.push(
                'Assignment Group changed from "' +
                previous.assignment_group.getDisplayValue() +
                '" to "' +
                current.assignment_group.getDisplayValue() +
                '"'
            );
        }


        if (current.state.changes()) {
            changes.push(
                'State changed from "' +
                previous.state.getDisplayValue() +
                '" to "' +
                current.state.getDisplayValue() +
                '"'
            );
        }


        if (current.escalation_level.changes()) {
            changes.push(
                'Escalation changed from "' +
                previous.escalation_level.getDisplayValue() +
                '" to "' +
                current.escalation_level.getDisplayValue() +
                '"'
            );
        }


        if (current.resolution_code.changes()) {
            changes.push(
                'Resolution Code changed from "' +
                previous.resolution_code.getDisplayValue() +
                '" to "' +
                current.resolution_code.getDisplayValue() +
                '"'
            );
        }


        if (changes.length > 0) {

            history.action_details = changes.join('\n');

            history.new_state = current.state.getDisplayValue();

            history.performed_by = gs.getUserID();

            history.action_date = new GlideDateTime();


            var result = history.insert();


            if (!result) {

                gs.error(
                    'Log Case Field Changes: Insert failed for case ' +
                    current.number
                );

            } else {

                gs.info(
                    'Complaint history created: ' +
                    result
                );

            }

        }


    } catch(ex) {

        gs.error(
            'Log Case Field Changes BR Error: ' +
            ex.message
        );

    }


})(current, previous);
